// Inject this into the browser console on the training page.
// This targets the primary video element, fast-forwards it to the end,
// and dispatches completion events to mimic natural playback finish.
// Note: This may not work if the LMS has server-side verification or additional checks.
// Use at your own risk; it's for educational purposes only.

(function() {
  const video = document.querySelector('video');
  if (!video) {
    console.error('No video element found. Check the page structure.');
    return;
  }

  // Fast-forward to the end
  video.currentTime = video.duration;
  video.playbackRate = 1; // Reset speed if altered

  // Dispatch events to simulate completion
  const endedEvent = new Event('ended', { bubbles: true });
  const timeupdateEvent = new Event('timeupdate', { bubbles: true });
  video.dispatchEvent(timeupdateEvent);
  video.dispatchEvent(endedEvent);

  // If there's a progress tracker or custom handler, try triggering it
  const progressElement = document.querySelector('[data-progress], .progress-bar, #progress');
  if (progressElement) {
    progressElement.style.width = '100%'; // Visual hack if applicable
    progressElement.setAttribute('aria-valuenow', '100');
  }

  // Listen for any potential LMS-specific events (common in systems like Moodle or Canvas)
  video.addEventListener('loadedmetadata', () => {
    video.currentTime = video.duration;
    video.dispatchEvent(endedEvent);
  });

  console.log('Video completion simulated. Check if the LMS advances.');
})();
